import bisect

class Solution:
    def countElements(self, nums: List[int], k: int) -> int:
        if k == 0:
            return len(nums)
        s = sorted(nums)
        n = len(nums)
        total = 0
        for x in nums:
            idx = bisect.bisect_right(s, x)
            if n - idx >= k:
                total += 1
        return total

