function bisectRight(arr, x) {
    let lo = 0, hi = arr.length;
    while (lo < hi) {
        const mid = (lo + hi) >> 1;
        if (arr[mid] <= x) lo = mid + 1; else hi = mid;
    }
    return lo;
}

var countElements = function(nums, k) {
    if (k === 0) return nums.length;
    const s = nums.slice().sort((a, b) => a - b);
    const n = nums.length;
    let total = 0;
    for (const x of nums) {
        const idx = bisectRight(s, x);
        if (n - idx >= k) total++;
    }
    return total;
};
